// This function offloads the heavy ZIP processing to a Web Worker
// to prevent the UI from freezing with large files.

export const processZipFiles = (files: File[]): Promise<{ blob: Blob; preview: string; data: any[] }> => {
    // The worker code is inlined as a string to create a Blob.
    // This avoids cross-origin issues when loading the worker script
    // in sandboxed environments.
    const workerCode = `
        // Use importScripts for classic workers, as 'import' is for module workers.
        self.importScripts('https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js');

        const processZipFilesInWorker = async (files) => {
            // Predefined language order for sorting the final output
            const LANGUAGE_ORDER = [
                'de-DE', 'en-AU', 'en-GB', 'es-419', 'es-ES', 'fi-FI', 'fr-CA', 
                'fr-FR', 'it-IT', 'ja-JP', 'ko-KR', 'nl-NL', 'pt-BR', 'pt-PT', 
                'zh-CN', 'zh-HK', 'zh-TW'
            ];

            // Regex for complex structures, e.g., 'en-US/trunk/opus_jsons/source.json' or 'en-US/trunk/opus_jsons/.../source.json'
            const complexStructureRegex = /([a-zA-Z]{2,3}(?:-[a-zA-Z0-9]{2,4})?)\\/trunk\\/opus_jsons\\/(?:.+\\/)?source\\.json$/;
            // Regex for simple structure, e.g., 'en-US.json'
            const simpleStructureRegex = /^([a-zA-Z]{2,3}(?:-[a-zA-Z0-9]{2,4})?)\\.json$/;

            const sourceFilePromises = [];

            // Iterate over all provided files
            for (const file of files) {
                let zip;
                try {
                    // Access JSZip from the global scope (self) after importScripts.
                    zip = await self.JSZip.loadAsync(file);
                } catch (e) {
                    throw new Error('Invalid ZIP file: ' + file.name + '. The file may be corrupt or not a valid ZIP archive.');
                }

                zip.forEach((relativePath, zipEntry) => {
                    if (zipEntry.dir) {
                        return;
                    }

                    let lang = null;
                    let match;

                    // Check for complex structure
                    match = relativePath.match(complexStructureRegex);
                    if (match) {
                        lang = match[1];
                    } else {
                        // Check for simple structure, possibly in a subdirectory
                        const pathSegments = relativePath.split('/');
                        const filename = pathSegments.pop();

                        // Ignore macOS resource fork files and hidden files
                        if (filename && !filename.startsWith('__MACOSX') && !filename.startsWith('.')) {
                            match = filename.match(simpleStructureRegex);
                            if (match) {
                                lang = match[1];
                            }
                        }
                    }

                    if (lang) {
                        const promise = (async () => {
                            try {
                                const content = await zipEntry.async('string');
                                const jsonData = JSON.parse(content);

                                let translationData;

                                if (Array.isArray(jsonData)) {
                                    // Support both existing key/value format and new opusID/stringValue format
                                    translationData = jsonData.reduce((acc, item) => {
                                        if (item) {
                                            if (typeof item.key === 'string' && typeof item.value === 'string') {
                                                // Existing format: { "key": "...", "value": "..." }
                                                acc.push({ key: item.key, value: item.value });
                                            } else if (typeof item.opusID === 'string' && typeof item.stringValue === 'string') {
                                                // New format: { "opusID": "...", "stringValue": "...", "pseudoHash": "..." }
                                                acc.push({ key: item.opusID, value: item.stringValue });
                                            }
                                        }
                                        return acc;
                                    }, []);
                                } else if (typeof jsonData === 'object' && jsonData !== null) {
                                    // Existing format: Flat object { "key": "value" }
                                    translationData = Object.entries(jsonData)
                                        .filter(([, value]) => typeof value === 'string')
                                        .map(([key, value]) => ({ key, value }));
                                } else {
                                    throw new Error('is not in a supported format. It must be a JSON array (key/value or opusID/stringValue) or a simple JSON object.');
                                }

                                return { lang, data: translationData };

                            } catch (e) {
                                 let errorMessage = e.message;
                                 if (e.name === 'SyntaxError') {
                                     errorMessage = 'The file contains invalid JSON.';
                                 }
                                 throw new Error("Error processing file for language '" + lang + "' (" + relativePath + ") in zip '" + file.name + "': " + errorMessage);
                            }
                        })();
                        sourceFilePromises.push(promise);
                    }
                });
            }

            if (sourceFilePromises.length === 0) {
                throw new Error("No valid translation files found in the provided ZIPs. Ensure the ZIP files contain either language-named JSON files (e.g., 'en-US.json') or follow a structure like 'en-US/trunk/opus_jsons/source.json'.");
            }

            const allLanguageData = await Promise.all(sourceFilePromises);

            const mergedData = new Map();
            const foundLangs = new Set();

            for (const { lang, data } of allLanguageData) {
                foundLangs.add(lang);
                for (const item of data) {
                    if (!mergedData.has(item.key)) {
                        mergedData.set(item.key, {});
                    }
                    const keyEntry = mergedData.get(item.key);
                    // If multiple zips have the same language, the later one overwrites.
                    // Or if a zip has multiple files for same language.
                    // Logic here: keyEntry[lang] = item.value
                    keyEntry[lang] = item.value;
                }
            }

            // Sort keys alphabetically
            const sortedKeys = Array.from(mergedData.keys()).sort();

            // Sort found languages based on the predefined order, ensuring en-US is always first
            const sortedLangs = Array.from(foundLangs).sort((a, b) => {
                // Requirement: en-US always comes first
                if (a === 'en-US') return -1;
                if (b === 'en-US') return 1;

                const indexA = LANGUAGE_ORDER.indexOf(a);
                const indexB = LANGUAGE_ORDER.indexOf(b);

                if (indexA !== -1 && indexB !== -1) {
                    return indexA - indexB; // Both are in the predefined list
                }
                if (indexA !== -1) {
                    return -1; // Only A is in the list, so A comes first
                }
                if (indexB !== -1) {
                    return 1; // Only B is in the list, so B comes first
                }
                return a.localeCompare(b); // Neither is in the list, sort alphabetically
            });

            // Build the final result with sorted keys and sorted languages
            const finalResult = sortedKeys.map(key => {
                const entry = { key };
                const languageValues = mergedData.get(key);
                for (const lang of sortedLangs) {
                    // Check if the key has a translation for this language
                    if (languageValues.hasOwnProperty(lang)) {
                        entry[lang] = languageValues[lang];
                    }
                }
                return entry;
            });

            const fullJsonString = JSON.stringify(finalResult, null, 2);
            const blob = new Blob([fullJsonString], { type: 'application/json' });

            const PREVIEW_LENGTH = 20000;
            let preview = fullJsonString;

            if (fullJsonString.length > PREVIEW_LENGTH) {
                preview = fullJsonString.substring(0, PREVIEW_LENGTH) + '\\n\\n[...]\\n\\n--- CONTENT TRUNCATED ---\\n\\n\\nThe full file is available for download.';
            }

            // Return blob, preview AND the structured data for filtering in the UI
            return { blob, preview, data: finalResult };
        };

        self.onmessage = async (event) => {
            const files = event.data;
            try {
                const result = await processZipFilesInWorker(files);
                // Post the result object back to the main thread.
                self.postMessage({ type: 'success', result });
            } catch (e) {
                const errorMessage = e.message || 'An unknown worker error occurred.';
                self.postMessage({ type: 'error', error: errorMessage });
            }
        };
    `;

    return new Promise((resolve, reject) => {
        const blob = new Blob([workerCode], { type: 'application/javascript' });
        const workerUrl = URL.createObjectURL(blob);

        const worker = new Worker(workerUrl);

        const cleanup = () => {
            URL.revokeObjectURL(workerUrl);
            worker.terminate();
        };

        worker.onmessage = (event: MessageEvent) => {
            const { type, result, error } = event.data;
            if (type === 'success') {
                resolve(result);
            } else if (type === 'error') {
                reject(new Error(error));
            }
            cleanup();
        };

        worker.onerror = (event: ErrorEvent) => {
            reject(new Error(`An error occurred in the processing worker: ${event.message}`));
            cleanup();
        };

        worker.postMessage(files);
    });
};

import React, { useState } from 'react';
import { Icon } from './Icon';

const LOCALE_LIST = [
    'en-US', 'de-DE', 'en-AU', 'en-GB', 'es-419', 'es-ES', 'fi-FI', 
    'fr-CA', 'fr-FR', 'it-IT', 'ja-JP', 'ko-KR', 'nl-NL', 'pt-BR', 
    'pt-PT', 'zh-CN', 'zh-HK', 'zh-TW'
];

interface LanguageSelectorProps {
    data: any[];
}

export const LanguageSelector: React.FC<LanguageSelectorProps> = ({ data }) => {
    // Default to all selected
    const [selected, setSelected] = useState<Set<string>>(new Set(LOCALE_LIST));

    const toggleLang = (lang: string) => {
        const newSet = new Set(selected);
        if (newSet.has(lang)) {
            newSet.delete(lang);
        } else {
            newSet.add(lang);
        }
        setSelected(newSet);
    };

    const handleSelectAll = () => setSelected(new Set(LOCALE_LIST));
    const handleDeselectAll = () => setSelected(new Set());

    const handleDownload = () => {
        if (selected.size === 0) return;

        const filteredData = data.map((item: any) => {
            const newItem: any = { key: item.key };
            // We iterate over the selected languages and grab them from the item if they exist
            selected.forEach(lang => {
                if (Object.prototype.hasOwnProperty.call(item, lang)) {
                    newItem[lang] = item[lang];
                }
            });
            return newItem;
        });

        const jsonString = JSON.stringify(filteredData, null, 2);
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = 'merged_selection.json';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    };

    return (
        <div className="mt-8 bg-slate-50 dark:bg-slate-900/50 rounded-xl p-6 border border-slate-200 dark:border-slate-700">
            <div className="flex flex-wrap items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-2">
                    <div className="p-2 bg-sky-100 dark:bg-sky-900/30 rounded-lg text-sky-600 dark:text-sky-400">
                        <Icon name="combine" className="w-5 h-5" />
                    </div>
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 dark:text-slate-200 leading-tight">
                            Custom Language Download
                        </h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400">Select specific languages to export</p>
                    </div>
                </div>
                <div className="flex gap-4">
                    <button 
                        onClick={handleSelectAll}
                        className="text-sm font-semibold text-sky-600 dark:text-sky-400 hover:text-sky-700 dark:hover:text-sky-300 transition-colors"
                    >
                        Select All
                    </button>
                    <button 
                        onClick={handleDeselectAll}
                        className="text-sm font-semibold text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300 transition-colors"
                    >
                        Deselect All
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-3 mb-8">
                {LOCALE_LIST.map(lang => {
                    const isSelected = selected.has(lang);
                    return (
                        <button
                            key={lang}
                            onClick={() => toggleLang(lang)}
                            className={`
                                relative px-3 py-2 text-sm font-medium rounded-lg transition-all duration-200 border text-center
                                ${isSelected 
                                    ? 'bg-sky-500 border-sky-500 text-white shadow-md shadow-sky-500/20' 
                                    : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:border-sky-300 dark:hover:border-sky-600 hover:bg-sky-50 dark:hover:bg-slate-700/50'
                                }
                            `}
                        >
                            {lang}
                        </button>
                    );
                })}
            </div>

            <div className="flex justify-end border-t border-slate-200 dark:border-slate-700 pt-6">
                <button
                    onClick={handleDownload}
                    disabled={selected.size === 0}
                    className={`
                        flex items-center gap-2 px-6 py-2.5 rounded-lg font-bold text-white transition-all duration-200
                        ${selected.size > 0 
                            ? 'bg-sky-500 hover:bg-sky-600 shadow-lg shadow-sky-500/25 transform hover:-translate-y-0.5 active:translate-y-0' 
                            : 'bg-slate-300 dark:bg-slate-700 cursor-not-allowed opacity-70'
                        }
                    `}
                >
                    <Icon name="download" className="w-5 h-5" />
                    Download Selected ({selected.size})
                </button>
            </div>
        </div>
    );
};

import React, { useState, useCallback } from 'react';
import { FileUpload } from './components/FileUpload';
import { ResultDisplay } from './components/ResultDisplay';
import { Spinner } from './components/Spinner';
import { ErrorMessage } from './components/ErrorMessage';
import { processZipFiles } from './services/zipProcessor';
import { Icon } from './components/Icon';
import { LanguageSelector } from './components/LanguageSelector';

const App: React.FC = () => {
    // We don't strictly need to store files in state for this logic, 
    // but useful if we want to display selected file names in the future.
    // For now, we process immediately.
    const [processing, setProcessing] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [result, setResult] = useState<{ blob: Blob; preview: string; data: any[] } | null>(null);

    const handleFilesChange = (selectedFiles: File[]) => {
        setError(null);
        setResult(null);
        if (selectedFiles && selectedFiles.length > 0) {
            handleProcessFiles(selectedFiles);
        }
    };

    const handleProcessFiles = useCallback(async (filesToProcess: File[]) => {
        if (!filesToProcess || filesToProcess.length === 0) return;

        setProcessing(true);
        setError(null);
        setResult(null);

        try {
            const jsonResult = await processZipFiles(filesToProcess);
            setResult(jsonResult);
        } catch (e: unknown) {
            if (e instanceof Error) {
                setError(e.message);
            } else {
                setError('An unexpected error occurred.');
            }
        } finally {
            setProcessing(false);
        }
    }, []);

    const resetState = () => {
        setProcessing(false);
        setError(null);
        setResult(null);
    };

    return (
        <div className="min-h-screen font-sans text-slate-800 dark:text-slate-200 flex flex-col items-center justify-center p-4">
            <div className="w-full max-w-4xl mx-auto">
                <header className="text-center mb-8">
                    <div className="flex items-center justify-center gap-3 mb-2">
                        <Icon name="combine" className="w-10 h-10 text-sky-500" />
                        <h1 className="text-4xl font-bold text-slate-900 dark:text-white">Localization JSON Merger</h1>
                    </div>
                    <p className="text-lg text-slate-600 dark:text-slate-400">
                        Upload one or more ZIP archives with language-specific JSON files to merge them into one.
                    </p>
                </header>

                <main className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl shadow-slate-200/50 dark:shadow-black/20 p-6 md:p-10 transition-all duration-300">
                    {!result && !processing && !error && (
                        <FileUpload onFileSelect={handleFilesChange} />
                    )}

                    {processing && (
                        <div className="flex flex-col items-center justify-center space-y-4 text-slate-600 dark:text-slate-400">
                            <Spinner />
                            <p className="text-lg font-medium">Processing your ZIP files...</p>
                            <p className="text-sm">This may take a moment.</p>
                        </div>
                    )}

                    {error && (
                        <ErrorMessage message={error} onClear={resetState} />
                    )}

                    {result && (
                        <div>
                            <div className="flex items-center justify-between mb-4">
                               <div className="flex items-center gap-2 text-green-600 dark:text-green-400">
                                   <Icon name="check" className="w-8 h-8"/>
                                   <h2 className="text-2xl font-semibold">Processing Complete!</h2>
                               </div>
                                <button
                                    onClick={resetState}
                                    className="px-4 py-2 text-sm font-semibold text-slate-700 bg-slate-200 hover:bg-slate-300 dark:bg-slate-700 dark:text-slate-200 dark:hover:bg-slate-600 rounded-md transition-colors"
                                >
                                    Process Another File
                                </button>
                            </div>
                            <ResultDisplay content={result.preview} blob={result.blob} />

                            <LanguageSelector data={result.data} />
                        </div>
                    )}
                </main>
                <footer className="text-center mt-8 text-slate-500 dark:text-slate-500 text-sm">
                    <p>Built with React, TypeScript, and Tailwind CSS.</p>
                </footer>
            </div>
        </div>
    );
};

export default App;

